<span class="line"><span style="color:#CBA6F7;">            let</span><span style="color:#CDD6F4;"> results </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> execute_tools</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">output</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">tool_calls</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
